scwin.f_BeforePopUpEd2 = function (nmObj, cdObj, gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    var cdObjVal = cdObj.getValue().trim();
    if (cdObjVal == "") {
        nmObj.setValue("");
    } else {
        nmObj.setValue("");
        var cd = nmObj;
        var nm = cdObj
        if (gubun1 == "DEPT") {
            scwin.f_OpenCommonPopUp('DEPT', 'T', 'F', 'F');
        } else {
            scwin.f_PopUp(gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF, cd, nm);
        }
    }
}

scwin.excel = async function () {
    if (ds_retrieve_result.getTotalRow() == 0) return;

    cfrm = await $c.win.confirm("수입서류 관리대장 목록을 EXCEL로 다운로드 받으시겠습니까?");
    if (!cfrm) return;
    $c.data.downloadGridViewExcel(gr_retrieve_result, { fileName: "수입서류 관리대장", sheetName: "수입서류 관리대장", hiddenVisible: true });
}

scwin.oneditkeyup = function (info, e) {
    this.setValue(e.target.value.toUpperCase());
};
//---------------------------------------------------------
// 컴포넌트 이벤트
//--------------------------------------------------------- 
scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.gr_retrieve_result_ontextimageclick = async function (rowIndex, columnIndex) {
    var data = {
        "houseNo": ds_retrieve_result.getCellData(ds_retrieve_result.getRowPosition() || 0, "hblno")
    }
    //상세화면 호출
    var opts = {
        id: "smpPop"
        , popupName: "첨부파일관리"
        , modal: true
        , type: "browserPopup"
        , width: 900
        , height: 650
        , title: "첨부파일관리"
    };
    var result = await $c.win.openPopup("/ui/il/common/xml/ilCommonFilePopup.xml", opts, data);

    scwin.f_Retrieve();
};

